var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"저건...... 클리포트의 마왕......?","JPN":"あれは……クリフォトの魔王……？","ENG":"Is that... a Demon Lord of Qliphoth?","TWN":"那是……逆卡巴拉魔王？"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L4_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"데이터베이스에서 본 적 있어...... 하지만 어째서 이런 곳에?","JPN":"データベースで見たことがある……しかし、なぜこんなところに？","ENG":"I've seen them in the database before... But what's it doing here?","TWN":"我在資料庫看過……但是，為什麼會在這裡？"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"서두르세요! 방주를 기동해서 여길 벗어나야 합니다!","JPN":"急いでください！　箱舟を起動してここを離れて！","ENG":"Hurry! We must activate the Ark and get out of here at once!","TWN":"快點！我們必須啟動方舟，趕快離開這裡！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"알렉스! 대원들과 함께 함선을 지키고 있어라!","JPN":"アレックス！　隊員たちと共に艦船の守りにつけ！","ENG":"Alex! Keep the ship secure with the troops!","TWN":"雅蕾克絲！和隊員們一起保護艦船！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"뭐? 넌 어떻게 하려고?","JPN":"えっ？　リュドミラちゃんはどうするの？","ENG":"What? What are you going to do?","TWN":"什麼？那妳要做什麼？"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"가서 시간을 벌겠다. 방주가 기동하기 전까지 저 괴물을 막아야 해.","JPN":"外に出て時間を稼ぐ。箱舟が起動するまであの化け物を止めなければ。","ENG":"I'm going to go buy us time. We must hold that monster at bay until the Ark is operational.","TWN":"我去爭取時間，在方舟啟動前，必須要擋下那個怪物。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"멍청한 소리 하지 마! 상대는 클리포트의 마왕이라고!","JPN":"バカ言わないで！　相手はクリフォトの魔王なのよ！","ENG":"Don't be stupid! This is a Demon Lord of Qliphoth we're talking about here!","TWN":"別說傻話了！對手是逆卡巴拉魔王啊！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"이래 봬도 관리국 전대장이다. 상대가 마왕이라고 해도 발목 정도는 잡을 수 있어.","JPN":"こう見えても管理局の戦隊長だ。\\nたとえ相手が魔王だろうと、足止めくらいは務められる。","ENG":"And I am a division commander of the Administration. Surely I'm capable of slowing down the enemy, even if it's a Demon Lord.","TWN":"別看我這樣，我可是管理局的戰隊隊長，就算對手是魔王，我也能夠拖住他。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"그리고 너희를 여기까지 데리고 온 이상, 책임은 져야지.","JPN":"それに君たちをここまで付き合わせた以上、責任は取らなければな。","ENG":"Besides, I must take responsibility for bringing you all here.","TWN":"而且，既然我把你們帶來了這裡，就一定要負起責任。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"지칠 대로 지친 상태로 뭘 어쩌겠다는 거야! 가 봤자 개죽음이라고!","JPN":"そんなヘトヘトな状態で何をするっていうの！\\n行ったって犬死にするだけだわ！","ENG":"You're already exhausted! There's not much you can do out there! You'll only get yourself killed!","TWN":"妳明明已經筋疲力盡了！妳去只是白白送死而已！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"그만둬! 류드밀라!!","JPN":"やめなさい！　リュドミラちゃん！！","ENG":"Don't! Lyudmila!!","TWN":"別去！盧德米拉！！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ASMODEUS_FALLEN_NS_NULL","text":{"KOREA":"후훗. 병정 개미들이 마중을 나와 주는군.","JPN":"ふふっ。兵隊アリがぞろぞろと迎え​に来てくれたわ。","ENG":"Heh heh. Looks like the soldier ants have come out to greet us.","TWN":"呵呵，兵蟻來迎接我了呢。"},"stage":{"bg":"SKY_RED","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASMODEUS_FALLEN_NS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ASMODEUS_FALLEN_NS_NULL","text":{"KOREA":"반갑구나, 힐데의 아이들아.","JPN":"会えたことを嬉しく思うぞ、ヒルデの子どもたちよ。","ENG":"Greetings, children of Hilde.","TWN":"真高興見到你們，希爾德的孩子們。"},"stage":{"bg":"SKY_RED","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASMODEUS_FALLEN_NS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ASMODEUS_FALLEN_NS_NULL","text":{"KOREA":"게다가 이런 곳에서 널 만나다니......","JPN":"それに、こんなところで其方に会えるとは……","ENG":"And to meet you in a place like this...","TWN":"而且，沒想到會在這裡遇到你……"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ASMODEUS_FALLEN_NS_NULL","text":{"KOREA":"오늘은 행운도 내게 고개를 조아리는군.","JPN":"今日は幸運までもが妾に首を垂れているようじゃ。","ENG":"It seems that even fortune is prostrating before me today.","TWN":"看來今天的我有幸運女神的眷顧呢。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"......세피라의 수호자들이 나타난 이상, <color=#ffd34c>그녀</color>도 강림했겠죠.","JPN":"……セフィラの守護者たちが現れた以上、\\n<color=#ffd34c>彼女</color>も降臨しているはずです。","ENG":"The appearance of the Guardians of Sephira very likely signifies <color=#ffd34c>her</color> advent as well.","TWN":"……既然塞菲拉守護者出現了，那麼<color=#ffd34c>她</color>應該也會降臨吧。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"마왕이라면 <color=#ffd34c>그녀</color>를 상대하러 가야 하는 것 아닙니까?","JPN":"魔王なのでしたら、<color=#ffd34c>彼女</color>の相手をしに行かれるべきでは？","ENG":"Shouldn't you be going off to face <color=#ffd34c>her</color> as a Demon Lord?","TWN":"身為魔王，不是應該去對付<color=#ffd34c>她</color>嗎？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"여기서 우리에게 낭비할 시간은 없을 텐데요?","JPN":"ここで僕たちに構っている暇はないのではありませんか？","ENG":"I don't think you can afford to waste your time on us.","TWN":"我想妳應該不會把時間浪費在我們身上吧？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ASMODEUS_FALLEN_NS_NULL","text":{"KOREA":"호오......","JPN":"ほう……","ENG":"Ah...","TWN":"哦……"},"stage":{"bg":"SKY_RED","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASMODEUS_FALLEN_NS_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ASMODEUS_FALLEN_NS_NULL","text":{"KOREA":"뒷조사를 많이 한 모양이군. 그 여자와 우리 사이가 어떤지도 알고 말이야.","JPN":"なかなかよく調べたものじゃ。\\nあの女と妾がどんな間柄かまで知っていようとは。","ENG":"So you've done your homework. You even know the nature of our relationship with her.","TWN":"看來你做了不少調查，居然知道那個女人以及我們之間的關係。"},"stage":{"bg":"SKY_RED","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASMODEUS_FALLEN_NS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ASMODEUS_FALLEN_NS_NULL","text":{"KOREA":"하지만 하나는 틀렸어.","JPN":"ただし、一つ間違えておる。","ENG":"But you're wrong about one thing.","TWN":"但有一點你說錯了。"},"stage":{"bg":"SKY_RED","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASMODEUS_FALLEN_NS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ASMODEUS_FALLEN_NS_NULL","text":{"KOREA":"나는 케케묵은 복수보다 네 스승에게 더 관심이 크거든.","JPN":"妾はカビの生えた復讐よりも、其方の師の方に興味があるのじゃ。","ENG":"I'm more interested in your Master than some age-old revenge.","TWN":"比起平凡的復仇，我對你的師父更有興趣。"},"stage":{"bg":"SKY_RED","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASMODEUS_FALLEN_NS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ASMODEUS_FALLEN_NS_NULL","text":{"KOREA":"그러고 보니 힐데가 안 보이는군. 어디에 있지?","JPN":"そういえばヒルデの姿が見当たらんのう。どこにおるのじゃ？","ENG":"Speaking of which, I do not see Hilde here. Where is she?","TWN":"話說我怎麼沒看到希爾德，她在哪裡？"},"stage":{"bg":"SKY_RED","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASMODEUS_FALLEN_NS_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ASMODEUS_FALLEN_NS_NULL","text":{"KOREA":"흥. 반응을 보아하니 또 너희들을 두고 가 버렸나? 세월이 흘러도 정말 변함없다니까.","JPN":"フン。その反応からするとまた置いてけぼりにされたのじゃな？\\n時が経とうが何一つ変わらんのう。","ENG":"Hmpf. Judging by your reaction, I suppose she's abandoned you again? Some things never change, I suppose.","TWN":"哼，看你這個反應，她又丟下你們了嗎？就算歲月流逝，她還真是一點都沒變。"},"stage":{"bg":"SKY_RED","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASMODEUS_FALLEN_NS_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ASMODEUS_FALLEN_NS_NULL","text":{"KOREA":"뭐, 그게 그 녀석의 매력이긴 하지만.","JPN":"まあ、それがあやつの魅力でもあるのじゃが。","ENG":"Then again, that's part of her charm.","TWN":"不過，這就是那傢伙的魅力。"},"stage":{"bg":"SKY_RED","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASMODEUS_FALLEN_NS_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"스승님을 찾아가실 겁니까?","JPN":"師匠を探しに行くつもりですか？","ENG":"Are you going to seek out my Master?","TWN":"妳要去找師父嗎？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"ASMODEUS_FALLEN_NS_NULL","text":{"KOREA":"물론이다. 하지만 그 전에......","JPN":"もちろんじゃ。だが、その前に……","ENG":"Of course. But before that...","TWN":"當然。不過，在那之前……"},"stage":{"bg":"SKY_RED","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASMODEUS_FALLEN_NS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"ASMODEUS_FALLEN_NS_NULL","text":{"KOREA":"마왕이면 마왕답게 조금은 잔혹한 모습을 보일 필요도 있겠지.","JPN":"魔王たる者らしく、少しは暴虐な一面も見せる必要があろう。","ENG":"I ought to show my cruel side as any proper Demon Lord should.","TWN":"魔王就得像個魔王，得展現她殘忍一面才行。"},"stage":{"bg":"SKY_RED","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASMODEUS_FALLEN_NS_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"ASMODEUS_FALLEN_NS_NULL","text":{"KOREA":"네 목을 들고 가면 힐데가 어떤 반응을 보일지 조금 궁금해지는걸.","JPN":"其方の素っ首を土産にすれば、ヒルデはどんな反応を見せてくれるかのう？","ENG":"I am curious to see Hilde's response if I bring her your severed head.","TWN":"如果我帶著你的首級去見希爾德的話，還真好奇她會有什麼反應呢。"},"stage":{"bg":"SKY_RED","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASMODEUS_FALLEN_NS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"헛소리는 집어치워라, 마왕.","JPN":"くだらない御託はよせ、魔王。","ENG":"Enough with your nonsense, Demon Lord.","TWN":"別廢話了，魔王。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL"},{"id":"L4_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"쉽게 당해 주진 않을 거다. 질릴 만큼 실컷 발버둥쳐 주지.","JPN":"みすみすやられると思うな。嫌と言うほど足掻き尽くしてやる。","ENG":"We won't go down so easily. We'll keep fighting until you grow tired of us.","TWN":"我們不會讓妳輕易得逞的，我們會全力掙扎到最後的。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"ASMODEUS_FALLEN_NS_NULL","text":{"KOREA":"아하하하하! 벌레 주제에 자신감이 대단하구나!","JPN":"アハハハハ！　虫の分際でえらい自信過剰じゃな！","ENG":"Ah hah hah hah hah! What remarkable confidence for a mere bug!","TWN":"啊哈哈哈哈！區區螻蟻還這麼囂張！"},"stage":{"bg":"SKY_RED","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASMODEUS_FALLEN_NS_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ASMODEUS_FALLEN_NS_NULL","text":{"KOREA":"짓밟을 맛이 나겠어.","JPN":"踏み潰し甲斐がありそうじゃ。","ENG":"I think I'll have fun stomping on you.","TWN":"看我怎麼把你們捏死。"},"stage":{"bg":"SKY_RED","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASMODEUS_FALLEN_NS_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ASMODEUS_FALLEN_NS_NULL","text":{"KOREA":"그래서, 고작 너희 둘로 날 막겠다고?","JPN":"で、たった二人でこの妾を止めるつもりかのう？","ENG":"So, just the two of you are going to try to stop me?","TWN":"所以，你們區區兩個人就想阻止我嗎？"},"stage":{"bg":"SKY_RED","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASMODEUS_FALLEN_NS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LEESUYEON_ADMIN_QM_NULL","text":{"KOREA":"둘이 아니야. 셋이지.","JPN":"二人じゃない。三人だよ。","ENG":"Not two. Three.","TWN":"不是兩個，是三個。"},"stage":{"bg":"SKY_RED","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASMODEUS_FALLEN_NS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ASMODEUS_FALLEN_NS_NULL","text":{"KOREA":"호오......?","JPN":"ほう……？","ENG":"Oh?","TWN":"哦……？"},"stage":{"bg":"SKY_RED","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASMODEUS_FALLEN_NS_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"이수연?!","JPN":"カナミ！？","ENG":"Lee Sooyeon?!","TWN":"李秀妍？！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L18_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"수연아!","JPN":"キズナ！","ENG":"Sooyeon!","TWN":"秀妍！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L20_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"뭘 멍청하게 보고 있어. 적은 저쪽이라고.","JPN":"何ポカンと見てるの？　敵はあっちだよ。","ENG":"Well, don't just stand there and stare at me! The enemy is over there.","TWN":"你們愣愣地看著幹嘛，敵人在那裡啊。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_TIRED"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"넌 지금 부상자야! 안정을 취해야 한다고!","JPN":"君は今負傷してる！　安静にしないといけないんだ！","ENG":"But you've been injured! You have to rest!","TWN":"妳受傷了！妳必須要靜養！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_TIRED"},"C":null,"R":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L24_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"그래서 나더러 침대에 누워 가만히 있으라고?","JPN":"だからってこの私にベッドでじっと寝てろって？","ENG":"You really expect me to lie in bed in this situation?","TWN":"所以你要我在床上乖乖躺著？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L25_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"싸우지 않으면 다 죽는 건 마찬가지잖아.","JPN":"戦わないと、どうせみんな死んじゃうんだよ。","ENG":"We're all dead anyway if we don't fight.","TWN":"不戰鬥的話不就跟死了沒兩樣嗎？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L26_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"그건......","JPN":"でも……","ENG":"But...","TWN":"但是……"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L27_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"걱정 마, 멀대. 이 정도 부상은 아무것도 아니야.","JPN":"心配しないで、ヒョロガリ君。\\nこの程度のケガは何でもないんだから。","ENG":"Don't worry, Beanstalk. This is just a flesh wound.","TWN":"別擔心，傻大個。這點傷不算什麼。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L29_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"그러니까...... 언제나 하던 대로 전방은 내가 맡을게.","JPN":"だから……いつも通り、前衛は私が務めるよ。","ENG":"So... I'll take point, as usual.","TWN":"所以……就像平時一樣，我來負責前方。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_TIRED"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL"},{"id":"L30_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"하지만 그래도 조금......","JPN":"でも、さすがにちょっと……","ENG":"To be honest though...","TWN":"但的確……"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"아주 조금 힘든 건 사실이니까......","JPN":"ちょっとだけ辛いのは確かなんだよね……","ENG":"I am feeling a tad under the weather...","TWN":"的確是有一點點吃力沒錯……"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"나 안 죽게, 뒤에서 잘 받쳐 줘.","JPN":"私だって死ぬつもりはないから、後ろでしっかりサポートしなさい。","ENG":"So make sure you back me up and keep me alive.","TWN":"我不會死的，你們就在後方好好支援我。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};